#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int mod = 998244353;
int n,m,k;
ll dp[2010][2010];
int main(){
    cin>>n>>m>>k;
    for(int i=1;i<=n;i++)dp[i][0]=1;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=min(k,i-1);j++){
            dp[i][j]=dp[i-1][j];
            if(j>=1)dp[i][j]+=dp[i-1][j-1]*m%mod;
            dp[i][j]%=mod;
        }
        for(int j=k+1;j<=i-1;j++){
            dp[i][j]=dp[i-1][j];
            if(j>=1)dp[i][j]+=dp[i-1][j-1]*(m-1)%mod;
            dp[i][j]%=mod;
        }
    }
    ll ans=0;
    for(int i=k;i<=n-1;i++){
        ans+=dp[n][i];
        ans%=mod;
    }
    cout<<ans<<endl;
    return 0;
}
